async function runAggregationQuery({ dataset, table, aggregationColumns, metricsColumns, dateRange, customQuery }) {
  console.log('Running primary aggregation query...');

  if (customQuery) {
    const [job] = await bigquery.createQueryJob({
      query: customQuery,
      location: 'US',
      maximumBytesBilled: '10000000000', // 10GB limit per query
      jobTimeoutMs: 480000, // 8 minutes
    });
    const [rows] = await job.getQueryResults({ maxResults: 1000000 });
    return { rowCount: rows.length, data: rows };
  }

  const metricsAgg = metricsColumns
    .map(
      (col) =>
        `SUM(${col}) as total_${col}, AVG(${col}) as avg_${col}, MIN(${col}) as min_${col}, MAX(${col}) as max_${col}, COUNT(DISTINCT ${col}) as distinct_${col}`
    )
    .join(', ');

  const groupByClause = aggregationColumns.join(', ');
  const dateFilter = buildDateFilter(dateRange);

  const query = `
    SELECT 
      ${groupByClause},
      COUNT(*) as record_count,
      ${metricsAgg}
    FROM \`${dataset}.${table}\`
    ${dateFilter ? `WHERE ${dateFilter}` : ''}
    GROUP BY ${groupByClause}
    ORDER BY record_count DESC
    LIMIT 100000
  `;

  const [job] = await bigquery.createQueryJob({
    query,
    location: 'US',
    maximumBytesBilled: '50000000000', // 50GB limit
    jobTimeoutMs: 480000,
  });

  const [rows] = await job.getQueryResults({ maxResults: 1000000 });

  console.log(`Primary aggregation returned ${rows.length} rows`);
  return { rowCount: rows.length, data: rows };
}

async function runStatisticalSummary({ dataset, table, metricsColumns, dateRange }) {
  console.log('Running statistical summary...');

  const dateFilter = buildDateFilter(dateRange);

  const statsExpressions = metricsColumns
    .map(
      (col) => `
    STRUCT(
      '${col}' as column_name,
      COUNT(${col}) as count,
      COUNT(DISTINCT ${col}) as distinct_count,
      SUM(${col}) as sum,
      AVG(${col}) as mean,
      STDDEV(${col}) as stddev,
      VARIANCE(${col}) as variance,
      MIN(${col}) as min_val,
      MAX(${col}) as max_val,
      APPROX_QUANTILES(${col}, 4)[OFFSET(2)] as median
    ) as ${col}_stats`
    )
    .join(', ');

  const query = `
    SELECT 
      COUNT(*) as total_records,
      ${statsExpressions}
    FROM \`${dataset}.${table}\`
    ${dateFilter ? `WHERE ${dateFilter}` : ''}
  `;

  try {
    const [job] = await bigquery.createQueryJob({
      query,
      location: 'US',
      maximumBytesBilled: '50000000000',
      jobTimeoutMs: 480000,
    });

    const [rows] = await job.getQueryResults();
    console.log('Statistical summary completed');
    return rows[0] || {};
  } catch (error) {
    console.error('Statistical summary failed:', error.message);
    return { error: error.message };
  }
}

async function runTimeSeriesAggregation({ dataset, table, metricsColumns, dateRange }) {
  console.log('Running time-series aggregation...');

  const dateFilter = buildDateFilter(dateRange);

  // Try to detect date/timestamp columns
  const schemaQuery = `
    SELECT column_name, data_type 
    FROM \`${dataset}.INFORMATION_SCHEMA.COLUMNS\` 
    WHERE table_name = '${table}' 
      AND data_type IN ('DATE', 'TIMESTAMP', 'DATETIME')
    LIMIT 1
  `;

  try {
    const [schemaJob] = await bigquery.createQueryJob({ query: schemaQuery, location: 'US' });
    const [schemaRows] = await schemaJob.getQueryResults();

    if (schemaRows.length === 0) {
      console.log('No date columns found, skipping time-series aggregation');
      return { message: 'No date/timestamp columns detected' };
    }

    const dateColumn = schemaRows[0].column_name;
    const dateType = schemaRows[0].data_type;

    const dateTrunc =
      dateType === 'TIMESTAMP' || dateType === 'DATETIME' ? `DATE(${dateColumn})` : dateColumn;

    const metricsAgg = metricsColumns
      .map((col) => `SUM(${col}) as total_${col}, AVG(${col}) as avg_${col}`)
      .join(', ');

    const query = `
      SELECT 
        ${dateTrunc} as date_period,
        COUNT(*) as record_count,
        ${metricsAgg}
      FROM \`${dataset}.${table}\`
      ${dateFilter ? `WHERE ${dateFilter}` : ''}
      GROUP BY date_period
      ORDER BY date_period DESC
      LIMIT 10000
    `;

    const [job] = await bigquery.createQueryJob({
      query,
      location: 'US',
      maximumBytesBilled: '50000000000',
      jobTimeoutMs: 480000,
    });

    const [rows] = await job.getQueryResults({ maxResults: 1000000 });
    console.log(`Time-series aggregation returned ${rows.length} rows`);
    return { dateColumn, rowCount: rows.length, data: rows };
  } catch (error) {
    console.error('Time-series aggregation failed:', error.message);
    return { error: error.message };
  }
}

async function runPercentileAnalysis({ dataset, table, metricsColumns, dateRange }) {
  console.log('Running percentile analysis...');

  const dateFilter = buildDateFilter(dateRange);

  const percentileExpressions = metricsColumns
    .map(
      (col) => `
    APPROX_QUANTILES(${col}, 100) as ${col}_percentiles`
    )
    .join(', ');

  const query = `
    SELECT 
      ${percentileExpressions}
    FROM \`${dataset}.${table}\`
    ${dateFilter ? `WHERE ${dateFilter}` : ''}
  `;

  try {
    const [job] = await bigquery.createQueryJob({
      query,
      location: 'US',
      maximumBytesBilled: '50000000000',
      jobTimeoutMs: 480000,
    });

    const [rows] = await job.getQueryResults();

    // Extract key percentiles (p10, p25, p50, p75, p90, p95, p99)
    const percentileResult = {};
    for (const col of metricsColumns) {
      const key = `${col}_percentiles`;
      if (rows[0] && rows[0][key]) {
        const values = rows[0][key];
        percentileResult[col] = {
          p10: values[10],
          p25: values[25],
          p50: values[50],
          p75: values[75],
          p90: values[90],
          p95: values[95],
          p99: values[99],
        };
      }
    }

    console.log('Percentile analysis completed');
    return percentileResult;
  } catch (error) {
    console.error('Percentile analysis failed:', error.message);
    return { error: error.message };
  }
}

async function processBatchAggregation({
  dataset,
  table,
  batchSize,
  totalRows,
  metricsColumns,
  aggregationColumns,
  dateRange,
}) {
  console.log(`Processing in batches of ${batchSize}...`);

  const totalBatches = Math.ceil(totalRows / batchSize);
  const maxBatches = Math.min(totalBatches, 50); // Cap at 50 batches to stay within timeout
  const dateFilter = buildDateFilter(dateRange);

  const accumulatedResults = {};
  let processedRows = 0;

  for (let batch = 0; batch < maxBatches; batch++) {
    const offset = batch * batchSize;

    // Check remaining time (leave 60s buffer)
    const elapsedMs = Date.now() - globalStartTime;
    if (elapsedMs > 470000) {
      console.log(`Approaching timeout, stopping at batch ${batch}/${maxBatches}`);
      break;
    }

    console.log(`Processing batch ${batch + 1}/${maxBatches} (offset: ${offset})`);
    console.log(`Memory: ${JSON.stringify(getMemoryUsage())}`);

    const metricsAgg = metricsColumns
      .map(
        (col) =>
          `SUM(CAST(${col} AS FLOAT64)) as total_${col}, COUNT(${col}) as count_${col}`
      )
      .join(', ');

    const groupByClause =
      aggregationColumns.length > 0 ? aggregationColumns.join(', ') : "'all'";
    const groupBySelect =
      aggregationColumns.length > 0
        ? aggregationColumns.join(', ')
        : "'all' as group_key";

    const query = `
      SELECT 
        ${groupBySelect},
        COUNT(*) as batch_count,
        ${metricsAgg}
      FROM (
        SELECT * FROM \`${dataset}.${table}\`
        ${dateFilter ? `WHERE ${dateFilter}` : ''}
        LIMIT ${batchSize} OFFSET ${offset}
      )
      GROUP BY ${groupByClause}
    `;

    try {
      const [job] = await bigquery.createQueryJob({
        query,
        location: 'US',
        maximumBytesBilled: '50000000000',
        jobTimeoutMs: 300000,
      });

      const [rows] = await job.getQueryResults({ maxResults: 1000000 });

      // Merge batch results into accumulated results
      for (const row of rows) {
        const key =
          aggregationColumns.length > 0
            ? aggregationColumns.map((col) => row[col]).join('|')
            : 'all';

        if (!accumulatedResults[key]) {
          accumulatedResults[key] = { record_count: 0 };
          for (const col of aggregationColumns) {
            accumulatedResults[key][col] = row[col];
          }
          for (const col of metricsColumns) {
            accumulatedResults[key][`total_${col}`] = 0;
            accumulatedResults[key][`count_${col}`] = 0;
          }
        }

        accumulatedResults[key].record_count += row.batch_count || 0;
        for (const col of metricsColumns) {
          accumulatedResults[key][`total_${col}`] += row[`total_${col}`] || 0;
          accumulatedResults[key][`count_${col}`] += row[`count_${col}`] || 0;
        }
      }

      processedRows += batchSize;

      // Force garbage collection if available
      if (global.gc) {
        global.gc();
      }
    } catch (error) {
      console.error(`Batch ${batch + 1} failed:`, error.message);
    }
  }

  // Calculate averages from accumulated totals
  const finalResults = Object.values(accumulatedResults).map((entry) => {
    const result = { ...entry };
    for (const col of metricsColumns) {
      result[`avg_${col}`] =
        result[`count_${col}`] > 0 ? result[`total_${col}`] / result[`count_${col}`] : 0;
    }
    return result;
  });

  console.log(`Batch processing completed. Processed ${processedRows} rows, ${Object.keys(accumulatedResults).length} groups`);

  return {
    batchesProcessed: Math.min(maxBatches, totalBatches),
    totalBatches,
    processedRows: Math.min(processedRows, totalRows),
    totalRows,
    uniqueGroups: finalResults.length,
    data: finalResults.slice(0, 10000), // Limit output size
  };
}

async function writeResultsToBigQuery({ outputDataset, outputTable, results }) {
  console.log(`Writing results to ${outputDataset}.${outputTable}...`);

  try {
    // Prepare rows for insertion
    const rows = [];
    const timestamp = new Date().toISOString();

    // Flatten primary aggregation results
    if (results.primary && results.primary.data) {
      for (const row of results.primary.data.slice(0, 50000)) {
        rows.push({
          aggregation_type: 'primary',
          data: JSON.stringify(row),
          processed_at: timestamp,
        });
      }
    }

    // Add statistical summary
    if (results.statistics && !results.statistics.error) {
      rows.push({
        aggregation_type: 'statistics',
        data: JSON.stringify(results.statistics),
        processed_at: timestamp,
      });
    }

    // Add time series data
    if (results.timeSeries && results.timeSeries.data) {
      for (const row of results.timeSeries.data.slice(0, 10000)) {
        rows.push({
          aggregation_type: 'time_series',
          data: JSON.stringify(row),
          processed_at: timestamp,
        });
      }
    }

    if (rows.length === 0) {
      console.log('No rows to write');
      return { rowsWritten: 0 };
    }

    // Ensure dataset exists
    const datasetRef = bigquery.dataset(outputDataset);
    const [datasetExists] = await datasetRef.exists();
    if (!datasetExists) {
      await bigquery.createDataset(outputDataset);
    }

    // Create or get table
    const tableRef = datasetRef.table(outputTable);
    const [tableExists] = await tableRef.exists();

    if (!tableExists) {
      const schema = {
        fields: [
          { name: 'aggregation_type', type: 'STRING' },
          { name: 'data', type: 'STRING' },
          { name: 'processed_at', type: 'TIMESTAMP' },
        ],
      };
      await datasetRef.createTable(outputTable, { schema });
    }

    // Insert rows in chunks to avoid size limits
    const chunkSize = 10000;
    let totalInserted = 0;

    for (let i = 0; i < rows.length; i += chunkSize) {
      const chunk = rows.slice(i, i + chunkSize);
      await tableRef.insert(chunk);
      totalInserted += chunk.length;
      console.log(`Inserted ${totalInserted}/${rows.length} rows`);
    }

    console.log(`Successfully wrote ${totalInserted} rows to ${outputDataset}.${outputTable}`);
    return { rowsWritten: totalInserted };
  } catch (error) {
    console.error('Failed to write results to BigQuery:', error.message);
    return { error: error.message, rowsWritten: 0 };
  }
}

function buildDateFilter(dateRange) {
  if (!dateRange || (!dateRange.startDate && !dateRange.endDate)) {
    return null;
  }

  const conditions = [];
  const dateColumn = dateRange.column || 'created_at';

  if (dateRange.startDate) {
    conditions.push(`${dateColumn} >= '${dateRange.startDate}'`);
  }
  if (dateRange.endDate) {
    conditions.push(`${dateColumn} <= '${dateRange.endDate}'`);
  }

  return conditions.join(' AND ');
}

function getMemoryUsage() {
  const usage = process.memoryUsage();
  return {
    rss: `${(usage.rss / 1024 / 1024).toFixed(2)} MB`,
    heapTotal: `${(usage.heapTotal / 1024 / 1024).toFixed(2)} MB`,
    heapUsed: `${(usage.heapUsed / 1024 / 1024).toFixed(2)} MB`,
    external: `${(usage.external / 1024 / 1024).toFixed(2)} MB`,
  };
}

